INSERT INTO heritage_item (id, title, description, category_id, region_id, cover_image, video_url, status, create_time, update_time) VALUES (1, '豫剧', '豫剧是中国五大戏曲剧种之一，发源于河南开封，是河南最具代表性的戏曲剧种。', 2, 1, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Henan%20Yu%20Opera%20performance%20traditional%20Chinese%20theater&image_size=landscape_16_9', '', 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), description = VALUES(description), category_id = VALUES(category_id), region_id = VALUES(region_id), cover_image = VALUES(cover_image), video_url = VALUES(video_url), status = VALUES(status), update_time = NOW();
INSERT INTO heritage_item (id, title, description, category_id, region_id, cover_image, video_url, status, create_time, update_time) VALUES (2, '少林功夫', '少林功夫是中国武术的重要流派之一，发源于河南嵩山少林寺，被誉为天下第一名刹的武术。', 7, 1, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Shaolin%20Kung%20Fu%20martial%20arts%20performance%20in%20Henan&image_size=landscape_16_9', '', 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), description = VALUES(description), category_id = VALUES(category_id), region_id = VALUES(region_id), cover_image = VALUES(cover_image), video_url = VALUES(video_url), status = VALUES(status), update_time = NOW();
INSERT INTO heritage_item (id, title, description, category_id, region_id, cover_image, video_url, status, create_time, update_time) VALUES (3, '洛阳牡丹', '洛阳牡丹是中国传统名花，被誉为花中之王，洛阳牡丹栽培历史悠久，品种繁多。', 4, 3, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Luoyang%20peony%20flowers%20blooming%20in%20garden%20Henan&image_size=landscape_16_9', '', 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), description = VALUES(description), category_id = VALUES(category_id), region_id = VALUES(region_id), cover_image = VALUES(cover_image), video_url = VALUES(video_url), status = VALUES(status), update_time = NOW();
INSERT INTO heritage_item (id, title, description, category_id, region_id, cover_image, video_url, status, create_time, update_time) VALUES (4, '开封汴绣', '开封汴绣是中国传统刺绣工艺之一，发源于河南开封，以其精湛的技艺和丰富的题材而闻名。', 3, 2, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Kaifeng%20embroidery%20traditional%20Chinese%20craft%20Henan&image_size=landscape_16_9', '', 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), description = VALUES(description), category_id = VALUES(category_id), region_id = VALUES(region_id), cover_image = VALUES(cover_image), video_url = VALUES(video_url), status = VALUES(status), update_time = NOW();
INSERT INTO heritage_item (id, title, description, category_id, region_id, cover_image, video_url, status, create_time, update_time) VALUES (5, '洛阳唐三彩', '洛阳唐三彩是中国古代陶瓷烧制工艺的珍品，全名唐代三彩釉陶器，是盛行于唐代的一种低温釉陶器。', 3, 3, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Luoyang%20Tri-colored%20pottery%20traditional%20Chinese%20craft&image_size=landscape_16_9', '', 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), description = VALUES(description), category_id = VALUES(category_id), region_id = VALUES(region_id), cover_image = VALUES(cover_image), video_url = VALUES(video_url), status = VALUES(status), update_time = NOW();
INSERT INTO heritage_item (id, title, description, category_id, region_id, cover_image, video_url, status, create_time, update_time) VALUES (6, '南阳烙画', '南阳烙画是一种传统民间工艺，用火烧热烙铁在物体上熨出烙痕作画，具有独特的艺术魅力。', 6, 13, 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Nanyang%20pyrography%20traditional%20Chinese%20art%20Henan&image_size=landscape_16_9', '', 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), description = VALUES(description), category_id = VALUES(category_id), region_id = VALUES(region_id), cover_image = VALUES(cover_image), video_url = VALUES(video_url), status = VALUES(status), update_time = NOW();
INSERT INTO culture_news (id, title, content, cover_image, date, type, status, create_time, update_time) VALUES (1, '河南非遗文化节隆重开幕', '由河南省文化和旅游厅主办的2024年河南非遗文化节在郑州隆重开幕，来自全省各地的非遗项目齐聚一堂，展示河南丰富多彩的非物质文化遗产。', 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Henan%20intangible%20cultural%20heritage%20festival%20opening%20ceremony&image_size=landscape_16_9', NULL, 1, 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content), cover_image = VALUES(cover_image), date = VALUES(date), type = VALUES(type), status = VALUES(status), update_time = NOW();
INSERT INTO culture_news (id, title, content, cover_image, date, type, status, create_time, update_time) VALUES (2, '少林功夫入选世界非遗名录', '喜讯！少林功夫成功入选联合国教科文组织人类非物质文化遗产代表作名录，成为河南又一张世界级文化名片。', 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Shaolin%20Kung%20Fu%20world%20heritage%20certification&image_size=landscape_16_9', NULL, 1, 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content), cover_image = VALUES(cover_image), date = VALUES(date), type = VALUES(type), status = VALUES(status), update_time = NOW();
INSERT INTO culture_news (id, title, content, cover_image, date, type, status, create_time, update_time) VALUES (3, '2024年河南非遗文化节', '由河南省文化和旅游厅主办的2024年河南非遗文化节将在郑州举行，届时将有来自全省各地的非遗项目展示和表演。', 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Henan%20intangible%20cultural%20heritage%20festival%202024&image_size=landscape_16_9', '2024-05-01 至 2024-05-15', 2, 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content), cover_image = VALUES(cover_image), date = VALUES(date), type = VALUES(type), status = VALUES(status), update_time = NOW();
INSERT INTO culture_news (id, title, content, cover_image, date, type, status, create_time, update_time) VALUES (4, '少林功夫表演周', '嵩山少林寺将举办为期一周的少林功夫表演活动，展示正宗少林功夫的精髓，并有互动体验环节。', 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Shaolin%20Kung%20Fu%20performance%20week&image_size=landscape_16_9', '2024-06-10 至 2024-06-16', 2, 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content), cover_image = VALUES(cover_image), date = VALUES(date), type = VALUES(type), status = VALUES(status), update_time = NOW();
INSERT INTO culture_news (id, title, content, cover_image, date, type, status, create_time, update_time) VALUES (5, '关于开展2024年非遗传承人培训的通知', '为进一步提升我省非遗传承人的技艺水平，省文化和旅游厅将于2024年3月开展非遗传承人培训活动，请各相关单位积极组织报名。', NULL, NULL, 3, 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content), cover_image = VALUES(cover_image), date = VALUES(date), type = VALUES(type), status = VALUES(status), update_time = NOW();
INSERT INTO culture_news (id, title, content, cover_image, date, type, status, create_time, update_time) VALUES (6, '2024年河南非遗保护专项资金申报指南', '2024年河南非遗保护专项资金申报工作已启动，详情请查看附件申报指南，申报截止日期为2024年2月28日。', NULL, NULL, 3, 1, NOW(), NOW()) ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content), cover_image = VALUES(cover_image), date = VALUES(date), type = VALUES(type), status = VALUES(status), update_time = NOW();
